using System;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;

public class EventBookingContext : DbContext
{
    public DbSet<Event> Events { get; set; }
    public DbSet<Purchase> Purchases { get; set; }

    public EventBookingContext(DbContextOptions<EventBookingContext> options) : base(options)
    {
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Event>()
            .Property(e => e.AvailableSeats)
            .IsConcurrencyToken();
    }
}

public class Event
{
    public int Id { get; set; }
    public string Name { get; set; }
    public int AvailableSeats { get; set; }
    public int TotalSeats { get; set; }
}

public class Purchase
{
    public int Id { get; set; }
    public int EventId { get; set; }
    public string UserId { get; set; }
    public int Quantity { get; set; }
    public DateTime PurchaseDate { get; set; }
}

public class TicketPurchaseResult
{
    public bool Success { get; set; }
    public string Message { get; set; }
    public int? PurchaseId { get; set; }
}

public class TicketBookingService
{
    private readonly EventBookingContext _context;
    private const int MaxRetries = 3;

    public TicketBookingService(EventBookingContext context)
    {
        _context = context;
    }

    public async Task<TicketPurchaseResult> PurchaseTicketsAsync(int eventId, string userId, int quantity)
    {
        if (quantity <= 0)
        {
            return new TicketPurchaseResult
            {
                Success = false,
                Message = "Quantity must be greater than zero"
            };
        }

        int retryCount = 0;
        
        while (retryCount < MaxRetries)
        {
            try
            {
                using var transaction = await _context.Database.BeginTransactionAsync(System.Data.IsolationLevel.Serializable);
                
                try
                {
                    var eventEntity = await _context.Events
                        .FirstOrDefaultAsync(e => e.Id == eventId);

                    if (eventEntity == null)
                    {
                        return new TicketPurchaseResult
                        {
                            Success = false,
                            Message = "Event not found"
                        };
                    }

                    if (eventEntity.AvailableSeats < quantity)
                    {
                        return new TicketPurchaseResult
                        {
                            Success = false,
                            Message = $"Insufficient seats available. Only {eventEntity.AvailableSeats} seats remaining"
                        };
                    }

                    eventEntity.AvailableSeats -= quantity;

                    var purchase = new Purchase
                    {
                        EventId = eventId,
                        UserId = userId,
                        Quantity = quantity,
                        PurchaseDate = DateTime.UtcNow
                    };

                    _context.Purchases.Add(purchase);
                    
                    await _context.SaveChangesAsync();
                    await transaction.CommitAsync();

                    return new TicketPurchaseResult
                    {
                        Success = true,
                        Message = "Purchase successful",
                        PurchaseId = purchase.Id
                    };
                }
                catch (DbUpdateConcurrencyException)
                {
                    await transaction.RollbackAsync();
                    retryCount++;
                    
                    if (retryCount >= MaxRetries)
                    {
                        return new TicketPurchaseResult
                        {
                            Success = false,
                            Message = "Unable to complete purchase due to high demand. Please try again"
                        };
                    }
                    
                    await Task.Delay(100 * retryCount);
                    
                    foreach (var entry in _context.ChangeTracker.Entries())
                    {
                        await entry.ReloadAsync();
                    }
                    
                    continue;
                }
                catch
                {
                    await transaction.RollbackAsync();
                    throw;
                }
            }
            catch (Exception ex)
            {
                return new TicketPurchaseResult
                {
                    Success = false,
                    Message = $"An error occurred: {ex.Message}"
                };
            }
        }

        return new TicketPurchaseResult
        {
            Success = false,
            Message = "Unable to complete purchase. Please try again"
        };
    }

    public async Task<TicketPurchaseResult> PurchaseTicketsWithRawSqlAsync(int eventId, string userId, int quantity)
    {
        if (quantity <= 0)
        {
            return new TicketPurchaseResult
            {
                Success = false,
                Message = "Quantity must be greater than zero"
            };
        }

        using var transaction = await _context.Database.BeginTransactionAsync();
        
        try
        {
            var rowsAffected = await _context.Database.ExecuteSqlInterpolatedAsync(
                $@"UPDATE Events 
                   SET AvailableSeats = AvailableSeats - {quantity}
                   WHERE Id = {eventId} AND AvailableSeats >= {quantity}");

            if (rowsAffected == 0)
            {
                var eventEntity = await _context.Events.FindAsync(eventId);
                
                if (eventEntity == null)
                {
                    return new TicketPurchaseResult
                    {
                        Success = false,
                        Message = "Event not found"
                    };
                }

                return new TicketPurchaseResult
                {
                    Success = false,
                    Message = $"Insufficient seats available"
                };
            }

            var purchase = new Purchase
            {
                EventId = eventId,
                UserId = userId,
                Quantity = quantity,
                PurchaseDate = DateTime.UtcNow
            };

            _context.Purchases.Add(purchase);
            await _context.SaveChangesAsync();
            await transaction.CommitAsync();

            return new TicketPurchaseResult
            {
                Success = true,
                Message = "Purchase successful",
                PurchaseId = purchase.Id
            };
        }
        catch (Exception ex)
        {
            await transaction.RollbackAsync();
            return new TicketPurchaseResult
            {
                Success = false,
                Message = $"An error occurred: {ex.Message}"
            };
        }
    }
